@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h1>Kanban Board</h1>

@if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">@errorMessage</div>
}
else if (allTasks is null)
{
    <p><em>Loading tasks...</em></p>
}
else
{
    <!-- Stats Bar -->
    <div class="stats-bar">
        <span class="stat-item">Total: <strong>@allTasks.Count</strong></span>
        <span class="stat-item">To Do: <strong>@GetColumnTasks("To Do").Count</strong></span>
        <span class="stat-item">In Progress: <strong>@GetColumnTasks("In Progress").Count</strong></span>
        <span class="stat-item">Done: <strong>@GetColumnTasks("Done").Count</strong></span>
        <span class="stat-item stat-overdue">Overdue: <strong>@allTasks.Count(t => t.DueDate < DateTime.Today)</strong></span>
    </div>

    <!-- Search Bar -->
    <div class="search-bar">
        <input type="text" class="form-control" placeholder="Search tasks by title..."
               @bind="searchQuery" @bind:event="oninput" />
    </div>

    <!-- Kanban Columns -->
    <div class="kanban-board">
        @foreach (var column in columns)
        {
            var tasks = GetFilteredColumnTasks(column);
            <div class="kanban-column">
                <div class="column-header">
                    <h3>@column</h3>
                    <span class="badge bg-secondary">@tasks.Count</span>
                </div>

                <div class="column-body">
                    @foreach (var task in tasks)
                    {
                        <div class="task-card">
                            <div class="task-title">@task.Title</div>
                            <div class="task-assignee">@task.Assignee</div>
                            <span class="priority-badge priority-@task.Priority.ToLowerInvariant()">@task.Priority</span>
                            <div class="task-due">@task.DueDate.ToString("MMM dd")</div>
                            <div class="task-actions">
                                @{ var colIndex = Array.IndexOf(columns, column); }
                                @if (colIndex > 0)
                                {
                                    var leftStatus = columns[colIndex - 1];
                                    <button class="btn btn-sm btn-outline-secondary"
                                            @onclick="() => MoveTask(task.Id, leftStatus)">
                                        &larr; Move Left
                                    </button>
                                }
                                @if (colIndex < columns.Length - 1)
                                {
                                    var rightStatus = columns[colIndex + 1];
                                    <button class="btn btn-sm btn-outline-secondary"
                                            @onclick="() => MoveTask(task.Id, rightStatus)">
                                        Move Right &rarr;
                                    </button>
                                }
                            </div>
                        </div>
                    }
                </div>

                @if (addingColumn == column)
                {
                    <div class="add-task-form">
                        <input type="text" class="form-control mb-1" placeholder="Title"
                               @bind="newTitle" />
                        <input type="text" class="form-control mb-1" placeholder="Assignee"
                               @bind="newAssignee" />
                        <select class="form-select mb-1" @bind="newPriority">
                            <option value="High">High</option>
                            <option value="Medium">Medium</option>
                            <option value="Low">Low</option>
                        </select>
                        <input type="date" class="form-control mb-1" @bind="newDueDate" />
                        <div class="d-flex gap-1">
                            <button class="btn btn-sm btn-primary" @onclick="SaveNewTask">Save</button>
                            <button class="btn btn-sm btn-secondary" @onclick="CancelAdd">Cancel</button>
                        </div>
                    </div>
                }
                else
                {
                    <button class="btn btn-sm btn-outline-primary add-task-btn"
                            @onclick="() => StartAdd(column)">
                        + Add Task
                    </button>
                }
            </div>
        }
    </div>
}

@code {
    private static readonly string[] columns = { "To Do", "In Progress", "Done" };

    private List<TaskItem>? allTasks;
    private string? errorMessage;
    private string searchQuery = string.Empty;

    // Add-task form state
    private string? addingColumn;
    private string newTitle = string.Empty;
    private string newAssignee = string.Empty;
    private string newPriority = "Medium";
    private DateTime newDueDate = DateTime.Today;

    protected override async Task OnInitializedAsync()
    {
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
    }

    private List<TaskItem> GetColumnTasks(string status)
        => allTasks!.Where(t => t.Status == status).ToList();

    private List<TaskItem> GetFilteredColumnTasks(string status)
    {
        var tasks = GetColumnTasks(status);
        if (!string.IsNullOrWhiteSpace(searchQuery))
        {
            tasks = tasks.Where(t => t.Title.Contains(searchQuery, StringComparison.OrdinalIgnoreCase)).ToList();
        }
        return tasks;
    }

    private async Task MoveTask(int taskId, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private void StartAdd(string column)
    {
        addingColumn = column;
        newTitle = string.Empty;
        newAssignee = string.Empty;
        newPriority = "Medium";
        newDueDate = DateTime.Today;
    }

    private void CancelAdd() => addingColumn = null;

    private async Task SaveNewTask()
    {
        if (string.IsNullOrWhiteSpace(newTitle) || addingColumn is null)
            return;

        try
        {
            await TaskService.CreateTaskAsync(newTitle, newAssignee, newPriority, newDueDate);
            allTasks = await TaskService.GetAllTasksAsync();
            addingColumn = null;
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to create task: {ex.Message}";
        }
    }
}

.stats-bar {
    display: flex;
    gap: 1.5rem;
    padding: 0.75rem 1rem;
    background: #f8f9fa;
    border-radius: 0.5rem;
    margin-bottom: 1rem;
    flex-wrap: wrap;
}

