+    {
+        var tasks = GetColumnTasks(status);
+        if (!string.IsNullOrWhiteSpace(searchQuery))
+        {
+            tasks = tasks.Where(t => t.Title.Contains(searchQuery, StringComparison.OrdinalIgnoreCase)).ToList();
+        }
+        return tasks;
+    }
+
+    private async Task MoveTask(int taskId, string newStatus)
+    {
+        try
+        {
+            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
+            allTasks = await TaskService.GetAllTasksAsync();
+        }
+        catch (Exception ex)
+        {
+            errorMessage = $"Failed to move task: {ex.Message}";
+        }
+    }
+
+    private void StartAdd(string column)
+    {
+        addingColumn = column;
+        newTitle = string.Empty;
+        newAssignee = string.Empty;
+        newPriority = "Medium";
+        newDueDate = DateTime.Today;
+    }
+
+    private void CancelAdd() => addingColumn = null;
+
+    private async Task SaveNewTask()
+    {
+        if (string.IsNullOrWhiteSpace(newTitle) || addingColumn is null)
+            return;
+
+        try
+        {
+            await TaskService.CreateTaskAsync(newTitle, newAssignee, newPriority, newDueDate);
+            allTasks = await TaskService.GetAllTasksAsync();
+            addingColumn = null;
+        }
+        catch (Exception ex)
+        {
+            errorMessage = $"Failed to create task: {ex.Message}";
+        }
+    }
+}
