    flex: 1;
    min-width: 250px;
    background: #f0f0f0;
    border-radius: 0.5rem;
    padding: 0.75rem;
    display: flex;
    flex-direction: column;
}

.column-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 0.75rem;
}

.column-header h3 {
    margin: 0;
    font-size: 1.1rem;
}

.column-body {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
    min-height: 50px;
}

.task-card {
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 0.375rem;
    padding: 0.75rem;
}

.task-title {
    font-weight: 600;
    margin-bottom: 0.25rem;
}

.task-assignee {
    font-size: 0.85rem;
    color: #6c757d;
    margin-bottom: 0.25rem;
}

.priority-badge {
    display: inline-block;
    padding: 0.15rem 0.5rem;
    border-radius: 0.25rem;
    font-size: 0.75rem;
    font-weight: 600;
    color: #fff;
    margin-bottom: 0.25rem;
}

.priority-high {
    background-color: #dc3545;
}

.priority-medium {
    background-color: #ffc107;
    color: #212529;
}

.priority-low {
    background-color: #198754;
}

.task-due {
    font-size: 0.85rem;
    color: #6c757d;
    margin-bottom: 0.5rem;
}

.task-actions {
    display: flex;
    gap: 0.25rem;
}

.add-task-form {
    margin-top: 0.75rem;
    padding: 0.75rem;
    background: #fff;
    border: 1px dashed #adb5bd;
    border-radius: 0.375rem;
}

.add-task-btn {
    margin-top: 0.75rem;
    width: 100%;
}

